import { useResetFormInput } from '@hooks';
import type { MultiSelectValue, SelectValue } from '@types';
import { useCallback, useContext, useRef, useState } from 'react';
import { FormContext } from '../../contexts';

import {
  getMultiSelectFormValues,
  getMultiSelectInitialValues,
  getMultiSelectUpdatedValues,
} from './MultiSelect.helpers';

export function useMultiSelectController({
  name,
  defaultValue,
  onChange,
  options,
}: {
  name: string;
  defaultValue?: string | number | readonly string[];
  onChange?: (values?: SelectValue[]) => void;
  options: SelectValue[];
}) {
  const [opened, setOpened] = useState(false);
  const { onChangeFormInput, initialValues } = useContext(FormContext);
  const initialOptions = getMultiSelectInitialValues({
    name,
    options,
    initialValues,
    defaultValue,
  });
  const [values, setValues] = useState<MultiSelectValue[]>(initialOptions);
  const onChangeFormInputRef = useRef(onChangeFormInput);
  const initialOptionsRef = useRef(initialOptions);

  // Update refs when values change
  onChangeFormInputRef.current = onChangeFormInput;
  initialOptionsRef.current = initialOptions;

  const handleClose = () => setOpened(false);

  const handleToggle = () => setOpened(!opened);

  const handleSelect = (id: string) => {
    const newValues = getMultiSelectUpdatedValues(values, id);

    setValues(newValues);
    onChange?.(newValues);
    onChangeFormInput?.({ name, value: getMultiSelectFormValues(newValues) });
  };

  const handleReset = useCallback(() => {
    setOpened(false);
    setValues(initialOptionsRef.current);
    onChangeFormInputRef.current?.({
      name,
      value: getMultiSelectFormValues(initialOptionsRef.current),
    });
  }, [name]);

  useResetFormInput(handleReset);

  return {
    handleClose,
    handleToggle,
    handleSelect,
    opened,
    values,
  };
}

import type { FormValues, MultiSelectValue, SelectValue } from '@types';

export function getMultiSelectInitialValues({
  name,
  options,
  initialValues,
  defaultValue,
}: {
  name: string;
  options: SelectValue[];
  initialValues?: FormValues;
  defaultValue?: string | number | readonly string[];
}): MultiSelectValue[] {
  return options.map((option) => {
    let selected = false;

    if (initialValues?.[name] && Array.isArray(initialValues[name])) {
      const selectedId = initialValues[name].find(
        (item) => item === option.id || item?.id === option.id,
      );
      if (selectedId) selected = true;
    }

    if (!initialValues?.[name] && Array.isArray(defaultValue)) {
      const selectedId = defaultValue.find((item) => item === option.id);
      if (selectedId) selected = true;
    }

    return { ...option, selected };
  });
}

export const getMultiSelectFormValues = (options: MultiSelectValue[]): string[] => {
  return options.filter((item) => item.selected).map((item) => item.id);
};

export const getMultiSelectUpdatedValues = (
  options: MultiSelectValue[],
  id: string,
): MultiSelectValue[] => {
  const targetItem = options.find((item) => item.id === id);
  return options.map((item) => {
    return item.id === id ? { ...item, selected: !targetItem?.selected } : item;
  });
};

