import { useResetFormInput } from '@hooks';
import type { ChopLogicRegExpWithFlags, TextInputValidator } from '@types';
import {
  type ChangeEvent,
  type ChangeEventHandler,
  useCallback,
  useContext,
  useRef,
  useState,
} from 'react';
import { FormContext } from '../../contexts';

import { getTextInputInitialValue, validateTextInputValue } from './TextInput.helpers';

export function useTextInputController({
  name,
  defaultValue,
  onChange,
  onClear,
  required,
  validator,
}: {
  name: string;
  required: boolean;
  validator?: ChopLogicRegExpWithFlags | TextInputValidator;
  defaultValue?: string | number | readonly string[];
  onChange?: ChangeEventHandler<HTMLInputElement>;
  onClear?: () => void;
}) {
  const { onChangeFormInput, initialValues } = useContext(FormContext);
  const initialValue = getTextInputInitialValue({ initialValues, defaultValue, name });
  const [value, setValue] = useState<string>(initialValue);
  const [valid, setValid] = useState<boolean>(true);
  const [passwordShown, setPasswordShown] = useState<boolean>(false);
  const onChangeFormInputRef = useRef(onChangeFormInput);
  const initialValueRef = useRef(initialValue);

  // Update refs when values change
  onChangeFormInputRef.current = onChangeFormInput;
  initialValueRef.current = initialValue;

  const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
    const value = event.target.value;
    const valid = validateTextInputValue({ value, required, validator });

    setValue(value);
    setValid(valid);
    onChangeFormInput?.({ name, value, valid });
    onChange?.(event);
  };

  const handleClear = () => {
    setValue('');
    setValid(true);
    onChangeFormInput?.({ name, value: '', valid: true });
    onClear?.();
  };

  const handleReset = useCallback(() => {
    setValue(initialValueRef.current);
    setValid(true);
    onChangeFormInputRef.current?.({ name, value: initialValueRef.current, valid: true });
  }, [name]);

  const togglePassword = () => {
    setPasswordShown(!passwordShown);
  };

  useResetFormInput(handleReset);

  return {
    value,
    valid,
    passwordShown,
    handleChange,
    handleClear,
    togglePassword,
  };
}

import type { ChopLogicRegExpWithFlags, FormValues, TextInputValidator } from '@types';

export function validateTextInputValue({
  value,
  required,
  validator,
}: {
  value: string;
  required: boolean;
  validator?: ChopLogicRegExpWithFlags | TextInputValidator;
}): boolean {
  if (required && !validator && !value.length) {
    return false;
  }

  if (validator && typeof validator === 'function') {
    return validator(value);
  }

  if (validator && typeof validator === 'object') {
    return new RegExp(validator.regexp, validator?.flags).test(value);
  }

  return true;
}

export function getTextInputInitialValue({
  name,
  initialValues,
  defaultValue,
}: {
  name: string;
  initialValues?: FormValues;
  defaultValue?: string | number | readonly string[];
}): string {
  if (initialValues?.[name]) {
    return (initialValues[name] as string).toString();
  }

  if (defaultValue && typeof defaultValue === 'string') {
    return defaultValue;
  }

  return '';
}

