import { type RefObject, useEffect, useState } from 'react';

import { useContainerDimensions } from '../use-container-dimensions/use-container-dimensions';

type useTooltipPositionParams = {
  wrapperRef: RefObject<HTMLElement | null>;
  tooltipRef: RefObject<HTMLElement | null>;
  isOpened: boolean;
  spacing?: number;
};

export const useTooltipPosition = ({
  wrapperRef,
  tooltipRef,
  isOpened,
  spacing = 4,
}: useTooltipPositionParams) => {
  const [position, setPosition] = useState({ top: 0, left: 0 });
  const { width: tooltipWidth, height: tooltipHeight } = useContainerDimensions({
    ref: tooltipRef,
    isVisible: isOpened,
  });

  useEffect(() => {
    if (!isOpened || !wrapperRef?.current) {
      return;
    }

    const updatePosition = () => {
      const rect = wrapperRef.current?.getBoundingClientRect();
      if (!rect) return;

      let top = Math.round(rect.bottom + spacing);
      // Center the tooltip horizontally under the wrapper
      let left = Math.round(rect.left + rect.width / 2 - tooltipWidth / 2);

      // Adjust position if tooltip goes beyond the viewport
      if (top + tooltipHeight > window.innerHeight) {
        top = Math.round(rect.top - tooltipHeight - spacing);
      }
      if (left + tooltipWidth > window.innerWidth) {
        left = Math.round(window.innerWidth - tooltipWidth - spacing);
      }
      if (left < 0) {
        left = spacing;
      }

      setPosition({ top, left });
    };

    // Initial position calculation
    updatePosition();

    // Set up resize observer for window changes
    const resizeObserver = new ResizeObserver(updatePosition);
    resizeObserver.observe(document.documentElement);

    return () => {
      resizeObserver.disconnect();
    };
  }, [isOpened, wrapperRef, tooltipHeight, tooltipWidth, spacing]);

  return position;
};

