    it('uses new onClose callback when dependency changes', () => {
      const onClose1 = vi.fn();
      const onClose2 = vi.fn();

      const { rerender } = renderHook(
        ({ onClose }) =>
          useRemainingTimer({
            isOpened: true,
            isHovered: false,
            onClose,
            autoCloseDelay: 200,
