      rerender({ onClose: onClose2 });

      act(() => {
        vi.advanceTimersByTime(200);
      });

      // New callback should have been called when timer completes
      expect(onClose2).toHaveBeenCalledOnce();
    });
  });

  describe('Edge Cases', () => {
    it('handles very small delays', () => {
      const onClose = vi.fn();
      renderHook(() =>
        useRemainingTimer({
          isOpened: true,
          isHovered: false,
