import { Form } from '@components/organisms';
import { fireEvent, render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, expect, it, vi } from 'vitest';

import NumericInput from '../NumericInput';

describe('NumericInput', () => {
  const testProps = {
    id: 'numeric-input',
    name: 'quantity',
    label: 'Quantity',
    style: { width: '400px' },
  };

  it('should match the snapshot', () => {
    const { asFragment } = render(<NumericInput {...testProps} />);
    expect(asFragment()).toMatchSnapshot();
  });

  it('should render correctly with default props', () => {
    render(<NumericInput {...testProps} />);

    // Check if the label is rendered
    expect(screen.getByText(/Quantity/i)).toBeInTheDocument();

    // Check if the input is rendered
    const input = screen.getByRole('spinbutton');
    expect(input).toBeInTheDocument();
    expect(input).toHaveAttribute('type', 'number');
  });

  it('displays the correct default value', () => {
    render(<NumericInput {...testProps} defaultValue={5} />);

    const input = screen.getByRole('spinbutton');
    expect(input).toHaveValue(5);
  });

  it('updates value when typing', () => {
    const handleChange = vi.fn();
    render(<NumericInput {...testProps} onChange={handleChange} />);

    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: '10' } });

    expect(input).toHaveValue(10);
    expect(handleChange).toHaveBeenCalledTimes(1);
  });

  it('applies disabled state correctly', () => {
    render(<NumericInput {...testProps} disabled />);

    const input = screen.getByRole('spinbutton');
    expect(input).toBeDisabled();
  });

  it('displays error message', () => {
    render(<NumericInput {...testProps} errorMessage="Invalid input" />);

    expect(screen.getByText(/Invalid input/i)).toBeInTheDocument();
  });

  it('shows required label', () => {
    render(<NumericInput {...testProps} required />);

    expect(screen.getByText('*')).toBeInTheDocument();
    expect(screen.getByRole('spinbutton')).toBeRequired();
  });

  it('handles min and max constraints', () => {
    render(<NumericInput {...testProps} min={1} max={10} />);

    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: '-1' } });
    expect(input).toHaveValue(-1);
    expect(input).toBeInvalid();

    fireEvent.change(input, { target: { value: '11' } });
    expect(input).toHaveValue(11);
    expect(input).toBeInvalid();
  });

  it('does not allow non-numeric input', () => {
    render(<NumericInput {...testProps} />);

    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: 'abc' } });

    expect(input).toHaveValue(0); // If non-numeric input is entered, it should revert to 0.
  });

  it('should respect step increment', () => {
    render(<NumericInput {...testProps} step={2} defaultValue={0} />);

    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: '4' } });

    expect(input).toHaveValue(4);
  });

  it('should allow step increment using custom spin buttons', async () => {
    render(<NumericInput {...testProps} step={3} defaultValue={0} />);

    await userEvent.click(screen.getByLabelText(`Increment value for ${testProps.label}`));
    await userEvent.click(screen.getByLabelText(`Increment value for ${testProps.label}`));

    expect(screen.getByRole('spinbutton')).toHaveValue(6);
  });

  it('should allow step decrement using custom spin buttons', async () => {
    render(<NumericInput {...testProps} step={5} defaultValue={0} />);

    await userEvent.click(screen.getByLabelText(`Decrement value for ${testProps.label}`));
    await userEvent.click(screen.getByLabelText(`Decrement value for ${testProps.label}`));

    expect(screen.getByRole('spinbutton')).toHaveValue(-10);
  });

  it('should not allow custom spin buttons if the input is disabled', () => {
    render(<NumericInput {...testProps} step={5} defaultValue={0} disabled />);

    expect(screen.getByLabelText(`Decrement value for ${testProps.label}`)).toBeDisabled();
    expect(screen.getByLabelText(`Increment value for ${testProps.label}`)).toBeDisabled();
  });

  it('should call increment and decrement callbacks', async () => {
    const mockedIncrementCallback = vi.fn();
    const mockedDecrementCallback = vi.fn();
    render(
      <NumericInput
        {...testProps}
        onIncrement={mockedIncrementCallback}
        onDecrement={mockedDecrementCallback}
      />,
    );

    await userEvent.click(screen.getByLabelText(`Increment value for ${testProps.label}`));
    await userEvent.click(screen.getByLabelText(`Decrement value for ${testProps.label}`));

    expect(mockedIncrementCallback).toHaveBeenCalledTimes(1);
    expect(mockedDecrementCallback).toHaveBeenCalledTimes(1);
  });

  it('should take an initial value from the form context', async () => {
    render(
      <Form initialValues={{ quantity: 13 }}>
        <NumericInput {...testProps} />
      </Form>,
    );
    const input = screen.getByRole('spinbutton');
    expect(input).toHaveValue(13);
  });

  it('should not show an error message by default', async () => {
    render(<NumericInput {...testProps} errorMessage="Incorrect value" />);
    const errorMessage = await screen.findByText('Incorrect value');
    expect(errorMessage).toHaveAttribute('aria-hidden', 'true');
  });

  it('should show an error message if the input value is invalid', async () => {
    render(
      <NumericInput
        {...testProps}
        validator={(age) => !!age && age >= 1 && age < 100}
        errorMessage="Incorrect value"
      />,
    );
    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: '123' } });
    const errorMessage = await screen.findByText('Incorrect value');
    expect(errorMessage).toHaveAttribute('aria-hidden', 'false');
  });

  it('should not show an error message if the input value is valid', async () => {
    render(
      <NumericInput
        {...testProps}
        validator={(age) => !!age && age >= 1 && age < 100}
        errorMessage="Incorrect value"
      />,
    );
    const input = screen.getByRole('spinbutton');
    fireEvent.change(input, { target: { value: '4' } });
    const errorMessage = await screen.findByText('Incorrect value');
    expect(errorMessage).toHaveAttribute('aria-hidden', 'true');
  });

  // Stateless mode tests
  describe('Stateless mode', () => {
    it('should use stateless value when stateless prop is true', () => {
      const { rerender } = render(
        <NumericInput {...testProps} stateless value={42} onChange={vi.fn()} />,
      );

      const input = screen.getByRole('spinbutton');
      expect(input).toHaveValue(42);

      rerender(<NumericInput {...testProps} stateless value={99} onChange={vi.fn()} />);
      expect(input).toHaveValue(99);
    });

    it('should call onChange when input changes in stateless mode', () => {
      const handleChange = vi.fn();
      render(<NumericInput {...testProps} stateless value={10} onChange={handleChange} />);

      const input = screen.getByRole('spinbutton');
      fireEvent.change(input, { target: { value: '15' } });

      expect(handleChange).toHaveBeenCalledTimes(1);
    });

    it('should use stateless min/max constraints when stateless is true', () => {
      render(
        <NumericInput {...testProps} stateless value={5} min={1} max={10} onChange={vi.fn()} />,
      );

      const input = screen.getByRole('spinbutton');
      expect(input).toHaveAttribute('min', '1');
      expect(input).toHaveAttribute('max', '10');
    });

    it('should call onIncrement in stateless mode', async () => {
      const mockedIncrement = vi.fn();
      render(
        <NumericInput
          {...testProps}
          stateless
          value={5}
          onChange={vi.fn()}
          onIncrement={mockedIncrement}
        />,
      );

      await userEvent.click(screen.getByLabelText(`Increment value for ${testProps.label}`));

      expect(mockedIncrement).toHaveBeenCalledTimes(1);
    });

    it('should call onDecrement in stateless mode', async () => {
      const mockedDecrement = vi.fn();
      render(
        <NumericInput
          {...testProps}
          stateless
          value={5}
          onChange={vi.fn()}
          onDecrement={mockedDecrement}
        />,
      );

      await userEvent.click(screen.getByLabelText(`Decrement value for ${testProps.label}`));

      expect(mockedDecrement).toHaveBeenCalledTimes(1);
    });

    it('should not update internal state when stateless is true', async () => {
      const { rerender } = render(
        <NumericInput {...testProps} stateless value={10} onChange={vi.fn()} />,
      );

      const input = screen.getByRole('spinbutton');
      fireEvent.change(input, { target: { value: '20' } });

      // Input should still show 10 because stateless mode doesn't update internal state
      expect(input).toHaveValue(10);

      // Only update when parent re-renders with new value
      rerender(<NumericInput {...testProps} stateless value={20} onChange={vi.fn()} />);
      expect(input).toHaveValue(20);
    });

    it('should render correctly with stateless mode and no value prop', () => {
      render(<NumericInput {...testProps} stateless onChange={vi.fn()} />);

      const input = screen.getByRole('spinbutton');
      expect(input).toBeInTheDocument();
      expect(input).toHaveValue(null);
    });
  });
});

