import { IconName } from '@enums';
import { render, screen } from '@testing-library/react';
import type { Breadcrumb } from '@types';
import { describe, expect, it } from 'vitest';
import Breadcrumbs from '../Breadcrumbs';

describe('Breadcrumbs', () => {
  const mockItems = [
    { label: 'Home', icon: IconName.Home, link: '/' },
    { label: 'Products', icon: IconName.Activity, link: '/products' },
    { label: 'Electronics', icon: IconName.Settings, link: '/products/electronics' },
    { label: 'Smartphones', icon: IconName.Phone },
  ];

  it('matches the snapshot', () => {
    const { asFragment } = render(<Breadcrumbs items={mockItems} />);
    expect(asFragment()).toMatchSnapshot();
  });

  it('renders null when items array is empty', () => {
    const { container } = render(<Breadcrumbs items={[]} />);
    expect(container.firstChild).toBeNull();
  });

  it('renders null when items is undefined', () => {
    const { container } = render(<Breadcrumbs items={undefined as unknown as Breadcrumb[]} />);
    expect(container.firstChild).toBeNull();
  });

  it('renders breadcrumbs with correct semantic structure', () => {
    render(<Breadcrumbs items={mockItems} />);

    const nav = screen.getByRole('navigation', { name: 'Breadcrumb' });
    expect(nav).toBeInTheDocument();

    const list = screen.getByRole('list');
    expect(list).toBeInTheDocument();

    const listItems = screen.getAllByRole('listitem');
    expect(listItems).toHaveLength(4);
  });

  it('renders links for all items except the last one', () => {
    render(<Breadcrumbs items={mockItems} />);

    const links = screen.getAllByRole('link');
    expect(links).toHaveLength(3);

    // Last item should not be a link
    const lastItem = screen.getByText('Smartphones');
    expect(lastItem).not.toHaveAttribute('href');
  });

  it('applies aria-current="page" to the last item', () => {
    render(<Breadcrumbs items={mockItems} />);

    const lastItem = screen.getByText('Smartphones');
    expect(lastItem).toHaveAttribute('aria-current', 'page');
  });

  it('does not apply aria-current to non-last items', () => {
    render(<Breadcrumbs items={mockItems} />);

    const homeItem = screen.getByText('Home');
    const productsItem = screen.getByText('Products');
    const electronicsItem = screen.getByText('Electronics');

    expect(homeItem).not.toHaveAttribute('aria-current');
    expect(productsItem).not.toHaveAttribute('aria-current');
    expect(electronicsItem).not.toHaveAttribute('aria-current');
  });

  it('renders separator icons between breadcrumb items', () => {
    render(<Breadcrumbs items={mockItems} />);

    const separatorIcons = screen.getAllByTestId('breadcrumb-separator');

    expect(separatorIcons).toHaveLength(3); // 3 separators for 4 items
  });

  it('passes correct href to link components', () => {
    render(<Breadcrumbs items={mockItems} />);

    const links = screen.getAllByRole('link');
    expect(links[0]).toHaveAttribute('href', '/');
    expect(links[1]).toHaveAttribute('href', '/products');
    expect(links[2]).toHaveAttribute('href', '/products/electronics');
  });

  it('handles items without icons', () => {
    const itemsWithoutIcons = [
      { label: 'Home', link: '/' },
      { label: 'About', link: '/about' },
      { label: 'Contact' },
    ];

    render(<Breadcrumbs items={itemsWithoutIcons} />);

    // Should still render separators
    const separatorIcons = screen.getAllByTestId('breadcrumb-separator');
    expect(separatorIcons).toHaveLength(2);
  });

  it('applies custom className', () => {
    const { container } = render(<Breadcrumbs items={mockItems} className="custom-breadcrumbs" />);

    const nav = container.querySelector('nav');
    expect(nav).toHaveClass('custom-breadcrumbs');
  });

  it('passes through additional HTML attributes', () => {
    const breadcrumbId = 'main-breadcrumbs';
    const { container } = render(
      <Breadcrumbs
        items={mockItems}
        id={breadcrumbId}
        title="Navigation breadcrumbs"
        tabIndex={0}
      />,
    );

    const nav = container.querySelector('nav');
    expect(nav).toHaveAttribute('id', breadcrumbId);
    expect(nav).toHaveAttribute('title', 'Navigation breadcrumbs');
    expect(nav).toHaveAttribute('tabindex', '0');
  });

  it('handles single breadcrumb item', () => {
    const singleItem = [{ label: 'Home', icon: IconName.Home }];

    render(<Breadcrumbs items={singleItem} />);

    // Should render the item without separator
    expect(screen.getByText('Home')).toBeInTheDocument();
    expect(screen.getByText('Home')).toHaveAttribute('aria-current', 'page');

    // No separator icons for single item
    const separatorIcons = screen
      .queryAllByTestId('breadcrumb-icon')
      .filter((icon) => icon.getAttribute('data-icon-name') === IconName.ChevronRight);
    expect(separatorIcons).toHaveLength(0);
  });

  it('handles two breadcrumb items', () => {
    const twoItems = [{ label: 'Home', link: '/' }, { label: 'Current' }];

    render(<Breadcrumbs items={twoItems} />);

    // Should have one link and one current page
    const links = screen.getAllByRole('link');
    expect(links).toHaveLength(1);
    expect(screen.getByText('Current')).toHaveAttribute('aria-current', 'page');

    // One separator
    const separatorIcons = screen.getAllByTestId('breadcrumb-separator');
    expect(separatorIcons).toHaveLength(1);
  });

  it('renders items in correct order', () => {
    render(<Breadcrumbs items={mockItems} />);

    const listItems = screen.getAllByRole('listitem');
    const texts = listItems.map((item) => item.textContent);

    expect(texts[0]).toContain('Home');
    expect(texts[1]).toContain('Products');
    expect(texts[2]).toContain('Electronics');
    expect(texts[3]).toContain('Smartphones');
  });
});

src/components/molecules/checkbox/__test.source:
import { Form } from '@components/organisms';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, expect, it, vi } from 'vitest';

import Checkbox from '../Checkbox';

describe('Checkbox', () => {
  const testProps = {
    id: 'test-checkbox-id',
    name: 'checkbox',
    label: 'Test label',
  };

  it('should render the input correctly', () => {
    const { asFragment } = render(<Checkbox {...testProps} />);
    expect(asFragment()).toMatchSnapshot();
  });

  it('should display the label', () => {
    render(<Checkbox {...testProps} />);
    expect(screen.getByText(testProps.label)).toBeInTheDocument();
  });

  it('should be enabled by default', () => {
    render(<Checkbox {...testProps} />);
    expect(screen.getByRole('checkbox')).toBeEnabled();
  });

  it('could be disable by prop', () => {
    render(<Checkbox {...testProps} disabled />);
    expect(screen.getByRole('checkbox')).toBeDisabled();
  });

  it('could be checked by default', () => {
    render(<Checkbox {...testProps} defaultChecked />);
    expect(screen.getByRole('checkbox')).toBeChecked();
  });

  it('should check and uncheck the checkbox on click', async () => {
    render(<Checkbox {...testProps} />);
    const checkbox = screen.getByRole('checkbox');
    expect(checkbox).not.toBeChecked();
    await userEvent.click(checkbox);
    expect(checkbox).toBeChecked();
    await userEvent.click(checkbox);
    expect(checkbox).not.toBeChecked();
  });

  it('should call onChange handler on click', async () => {
    const mockOnChange = vi.fn();
    render(<Checkbox {...testProps} onChange={mockOnChange} />);
    const checkbox = screen.getByRole('checkbox');
    await userEvent.click(checkbox);
    expect(mockOnChange).toHaveBeenCalledOnce();
  });

  it('should call onChange handler on Space key press', async () => {
    const mockOnChange = vi.fn();
    render(<Checkbox {...testProps} onChange={mockOnChange} />);
    const checkbox = screen.getByRole('checkbox');
    checkbox.focus();
    await userEvent.keyboard('[Space]');
    expect(mockOnChange).toHaveBeenCalledOnce();
  });

  it('should take an initial value from the form context', async () => {
    render(
      <Form initialValues={{ checkbox: true }}>
        <Checkbox {...testProps} />
      </Form>,
    );
    expect(screen.getByRole('checkbox')).toBeChecked();
  });

  it('should ignore the defaultChecked prop is initial values is provided from the form context', async () => {
    render(
      <Form initialValues={{ checkbox: false }}>
        <Checkbox {...testProps} defaultChecked />
      </Form>,
    );
    expect(screen.getByRole('checkbox')).not.toBeChecked();
  });

  // Stateless mode tests
  describe('Stateless mode', () => {
    it('should use stateless checked prop when stateless is true', () => {
      const { rerender } = render(
        <Checkbox {...testProps} stateless checked={true} onChange={vi.fn()} />,
      );

      const checkbox = screen.getByRole('checkbox');
      expect(checkbox).toBeChecked();

      rerender(<Checkbox {...testProps} stateless checked={false} onChange={vi.fn()} />);
      expect(checkbox).not.toBeChecked();
    });

    it('should call onChange when checkbox is toggled in stateless mode', async () => {
      const handleChange = vi.fn();
      render(<Checkbox {...testProps} stateless checked={false} onChange={handleChange} />);

      const checkbox = screen.getByRole('checkbox');
      await userEvent.click(checkbox);

      expect(handleChange).toHaveBeenCalledTimes(1);
    });

    it('should not update internal state when stateless is true', async () => {
      const { rerender } = render(
        <Checkbox {...testProps} stateless checked={false} onChange={vi.fn()} />,
      );

      const checkbox = screen.getByRole('checkbox');
      await userEvent.click(checkbox);

      // Checkbox should still be unchecked because stateless mode doesn't update internal state
      expect(checkbox).not.toBeChecked();

      // Only update when parent re-renders with new checked value
      rerender(<Checkbox {...testProps} stateless checked={true} onChange={vi.fn()} />);
      expect(checkbox).toBeChecked();
    });

    it('should render correctly with stateless mode and no checked prop', () => {
      render(<Checkbox {...testProps} stateless onChange={vi.fn()} />);

      const checkbox = screen.getByRole('checkbox');
      expect(checkbox).toBeInTheDocument();
      expect(checkbox).not.toBeChecked();
    });

    it('should be disabled in stateless mode when disabled prop is true', () => {
      render(<Checkbox {...testProps} stateless checked={false} disabled onChange={vi.fn()} />);
      expect(screen.getByRole('checkbox')).toBeDisabled();
    });

    it('should toggle on Space key press in stateless mode', async () => {
      const mockOnChange = vi.fn();
      render(<Checkbox {...testProps} stateless checked={false} onChange={mockOnChange} />);
      const checkbox = screen.getByRole('checkbox');
      checkbox.focus();
      await userEvent.keyboard('[Space]');
      expect(mockOnChange).toHaveBeenCalledOnce();
    });
  });
});

src/components/atoms/link/__tests__/Link.source:
import { IconName } from '@enums';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { beforeEach, describe, expect, it, vi } from 'vitest';

import Link from '../Link';

// Mock the Icon component
vi.mock('@components/atoms', () => ({
  Icon: vi.fn(({ className }) => (
    <span className={className} aria-hidden={true} data-testid="mock-icon" />
  )),
}));

describe('Link', () => {
  const defaultProps = {
    href: 'https://example.com',
    children: 'Example Link',
    target: '_blank',
    rel: 'noopener noreferrer',
    onClick: vi.fn(),
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders the link with correct href and text', () => {
    render(<Link {...defaultProps} />);

    const link = screen.getByRole('link');
    expect(link).toBeInTheDocument();
    expect(link).toHaveAttribute('href', 'https://example.com');
  });

  it('applies target and rel attributes', () => {
    render(<Link {...defaultProps} />);

    const link = screen.getByRole('link');
    expect(link).toHaveAttribute('target', '_blank');
    expect(link).toHaveAttribute('rel', 'noopener noreferrer');
  });

  it('calls onClick handler when clicked', async () => {
    render(<Link {...defaultProps} />);

    const link = screen.getByRole('link');
    await userEvent.click(link);

    expect(defaultProps.onClick).toHaveBeenCalledTimes(1);
  });

  it('renders children correctly', () => {
    render(<Link {...defaultProps}>Custom Text</Link>);

    const link = screen.getByRole('link');
    expect(link).toBeInTheDocument();
  });

  it('does not throw error when onClick is not provided', async () => {
    const { href, children, target, rel } = defaultProps;
    render(
      <Link href={href} target={target} rel={rel}>
        {children}
      </Link>,
    );

    const link = screen.getByRole('link');
    await userEvent.click(link);

    expect(link).toBeInTheDocument();
  });

  describe('target handling', () => {
    it('sets _blank target for external links without explicit target', () => {
      render(<Link href="https://example.com">External Link</Link>);
      expect(screen.getByRole('link')).toHaveAttribute('target', '_blank');
    });

    it('uses provided target for external links', () => {
      render(
        <Link href="https://example.com" target="_self">
          External Link
        </Link>,
      );
      expect(screen.getByRole('link')).toHaveAttribute('target', '_self');
    });

    it('keeps target undefined for internal links', () => {
      render(<Link href="/internal">Internal Link</Link>);
      const link = screen.getByRole('link');
      expect(link.getAttribute('target')).toBeNull();
    });

    it('sets target to _blank for URLs starting with //', () => {
      render(<Link href="//example.com">Protocol-relative Link</Link>);
      expect(screen.getByRole('link')).toHaveAttribute('target', '_blank');
    });
  });

  describe('icon rendering', () => {
    it('renders icon on the left by default', () => {
      render(
        <Link {...defaultProps} icon={IconName.Search}>
          With Icon
        </Link>,
      );
      const icon = screen.getByTestId('mock-icon');
      const text = screen.getByText('With Icon');
      expect(icon.compareDocumentPosition(text)).toBe(Node.DOCUMENT_POSITION_FOLLOWING);
    });

    it('renders icon on the right when specified', () => {
      render(
        <Link {...defaultProps} icon={IconName.Search} iconPosition="right">
          With Icon
        </Link>,
      );
      const icon = screen.getByTestId('mock-icon');
      const text = screen.getByText('With Icon');
      expect(icon.compareDocumentPosition(text)).toBe(Node.DOCUMENT_POSITION_PRECEDING);
    });

    it('applies correct aria-hidden to icon', () => {
      render(
        <Link {...defaultProps} icon={IconName.Search}>
          With Icon
        </Link>,
      );
      expect(screen.getByTestId('mock-icon')).toHaveAttribute('aria-hidden', 'true');
    });

    it('does not render icon when not provided', () => {
      render(<Link {...defaultProps}>No Icon</Link>);
      expect(screen.queryByTestId('mock-icon')).not.toBeInTheDocument();
    });
  });

  describe('aria-label handling', () => {
    it('adds (opens in new window) to aria-label for string children', () => {
      render(<Link href="https://example.com">Visit Site</Link>);
      expect(screen.getByRole('link')).toHaveAttribute(
        'aria-label',
        'Visit Site (opens in new window)',
      );
    });

    it('uses generic aria-label for non-string children', () => {
      render(
        <Link href="https://example.com">
          <span>Complex Content</span>
        </Link>,
      );
      expect(screen.getByRole('link')).toHaveAttribute('aria-label', 'Opens in new window');
    });

    it('does not add aria-label for internal links', () => {
      render(<Link href="/internal">Internal Link</Link>);
      expect(screen.getByRole('link')).not.toHaveAttribute('aria-label');
    });
  });
});

