import { render } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { useRef } from 'react';
import { describe, expect, it, vi } from 'vitest';

import { useKeyPress } from '../use-key-press';

const TestComponent = ({ keyCode, onKeyPress }: { keyCode: string; onKeyPress: () => void }) => {
  const ref = useRef<HTMLDivElement>(null);
  useKeyPress({ ref, keyCode, onKeyPress });

  return (
    <div ref={ref} data-testid="test-element">
      Test Text
    </div>
  );
};

describe('useKeyPress  tests:', () => {
  it('should call onKeyPress handler when the specific key is pressed', async () => {
    const onKeyPress = vi.fn();
    const keyCode = 'Escape';

    const { getByTestId } = render(<TestComponent keyCode={keyCode} onKeyPress={onKeyPress} />);

    const testElement = getByTestId('test-element');

    // Focus the test element to ensure ref is current
    testElement.focus();

    // Simulate pressing the specific key
    await userEvent.keyboard(`{${keyCode}}`);

    expect(onKeyPress).toHaveBeenCalled();
  });

  it('should not call onKeyPress handler when a different key is pressed', async () => {
    const onKeyPress = vi.fn();
    const keyCode = 'Escape';

    const { getByTestId } = render(<TestComponent keyCode={keyCode} onKeyPress={onKeyPress} />);

    const testElement = getByTestId('test-element');

    // Focus the test element to ensure ref is current
    testElement.focus();

    // Simulate pressing a different key
    await userEvent.keyboard('[Enter]');

    expect(onKeyPress).not.toHaveBeenCalled();
  });
});

src/hooks/use-element-ids/__tests__/use-.source:
import { renderHook } from '@testing-library/react';
import { useId } from 'react';
import { beforeEach, describe, expect, it, type Mock, vi } from 'vitest';

import { useElementIds } from '../use-element-ids';

// Mock the useId hook
vi.mock('react', async () => {
  const actual = await vi.importActual('react');
  return {
    ...actual,
    useId: vi.fn(),
  };
});

describe('useElementIds', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should return elementId, errorId, and dropdownId based on provided id', () => {
    const customId = 'custom-element-id';
    const { result } = renderHook(() => useElementIds(customId));

    expect(result.current.elementId).toBe(customId);
    expect(result.current.errorId).toBe(`${customId}_error`);
    expect(result.current.dropdownId).toBe(`${customId}_dropdown`);
  });

  it('should return elementId, errorId, and dropdownId based on generated id if no id is provided', () => {
    const mockGeneratedId = 'random-generated-id';
    (useId as Mock).mockReturnValue(mockGeneratedId);

    const { result } = renderHook(() => useElementIds());

    expect(result.current.elementId).toBe(mockGeneratedId);
    expect(result.current.errorId).toBe(`${mockGeneratedId}_error`);
    expect(result.current.dropdownId).toBe(`${mockGeneratedId}_dropdown`);
  });

  it('should call useId when no id is provided', () => {
    const mockGeneratedId = 'random-generated-id';
    (useId as Mock).mockReturnValue(mockGeneratedId);

    renderHook(() => useElementIds());

    expect(useId).toHaveBeenCalled();
  });
});

